Ah, I found the issue! If you were to change `retry_call` to be `FnOnce`, then you can avoid the clone. But of course, it needs to be `Fn` because you call the function multiple times.

```diff
diff --git a/src/rust/engine/fs/store/src/remote.rs b/src/rust/engine/fs/store/src/remote.rs
index 43e5fbecb..d68ab59dc 100644
--- a/src/rust/engine/fs/store/src/remote.rs
+++ b/src/rust/engine/fs/store/src/remote.rs
@@ -365,7 +365,7 @@ impl ByteStore {
       let store2 = store.clone();
       let client = store2.cas_client.as_ref().clone();
       let response = retry_call(client, move |mut client| {
-        let request = request.clone();
+        // let request = request.clone();
         async move { client.find_missing_blobs(request).await }
       })
       .await
diff --git a/src/rust/engine/grpc_util/src/retry.rs b/src/rust/engine/grpc_util/src/retry.rs
index 60f817b83..8680be2f5 100644
--- a/src/rust/engine/grpc_util/src/retry.rs
+++ b/src/rust/engine/grpc_util/src/retry.rs
@@ -24,16 +24,17 @@ fn is_retryable(status: &Status) -> bool {
 pub async fn retry_call<T, C, F, Fut>(client: C, f: F) -> Result<Response<T>, Status>
 where
   C: Clone,
-  F: Fn(C) -> Fut,
+  F: FnOnce(C) -> Fut,
   Fut: Future<Output = Result<Response<T>, Status>>,
 {
