Could be like this
```
class Batcher:
    def __init__(self, batch_size):
        self.batch_size = batch_size
        self.buffer = []

    def add(self, batch):
        self.buffer.append(batch)

    def has_next(self):
        return sum(b.num_rows() for b in self.buffer) >= self.batch_size

    def next_batch(self):
        output = []
        leftover = []
        needed = self.batch_size

        for b in self.buffer:
            if needed <= 0:
                # Don't need
                leftover.append(b)
            elif b.num_rows() <= needed:
                # Need the entire batch
                leftover.append(b)
                output.append(b)
                needed -= b.num_rows()
            else:
                # Need the partial batch
                output.append(b.slice(0, needed))
                leftover.append(b.slice(needed, b.num_rows()))
                needed = 0

        self.buffer = leftover
        return concat(output)
```

